<span class="line"><span style="color:#A6ACCD;">    resp</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">getWriter</span><span style="color:#89DDFF;">().</span><span style="color:#82AAFF;">write</span><span style="color:#89DDFF;">(</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">当前 Session 已经设置为 3 秒后超时</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">);</span></span>
